 * fmemopen permet de simuler un fichier en mémoire
 * ================================================= */
void example_modes(void) {
    char demo[64];
    memset(demo, 0, sizeof(demo));
    FILE *f = fmemopen(demo, sizeof(demo), "w");
    fprintf(f, "ABC");
    fclose(f);
    printf("demo after w: %s\n", demo); /* ABC */

    f = fmemopen(demo, sizeof(demo), "a");
    fprintf(f, "DEF");
    fclose(f);
    printf("demo after a: %s\n", demo); /* ABCDEF */
